const body = $json.body ?? $json;
const required = ['submissionId', 'leadName', 'phone', 'caseType'];
const missing = required.filter((key) => !body[key]);
if (missing.length) {
  throw new Error(`Missing Fillout fields: ${missing.join(', ')}`);
}
const borrowerProfiles = Array.isArray(body.borrowerProfiles) ? body.borrowerProfiles : [body.borrowerProfiles].filter(Boolean);
const bankTargets = Array.isArray(body.bankTargets) ? body.bankTargets : String(body.bankTargets || '').split(',').map((x) => x.trim()).filter(Boolean);
const catalog = [
  { code: 'id-card', labelEn: 'ID card' },
  { code: 'advisor-authorization', labelEn: 'Advisor authorization letter' },
  { code: 'bank-statements-3m', labelEn: 'Bank statements - last 3 months' },
  { code: 'loan-summary', labelEn: 'Existing loan summary' },
  { code: 'tabu-extract', labelEn: 'Land registry extract' },
];
if (borrowerProfiles.includes('salaried')) catalog.push({ code: 'payslips-3m', labelEn: 'Last 3 payslips' });
if (borrowerProfiles.includes('self-employed')) catalog.push({ code: 'accountant-confirmation', labelEn: 'CPA confirmation' });
if (borrowerProfiles.includes('student')) catalog.push({ code: 'study-confirmation', labelEn: 'Study confirmation' });
if (borrowerProfiles.includes('benefits')) catalog.push({ code: 'benefits-confirmation', labelEn: 'Benefits confirmation' });
if (['purchase-single-dwelling','purchase-replacement-dwelling','purchase-investment-dwelling','discounted-program'].includes(body.caseType)) {
  catalog.push({ code: 'sale-agreement', labelEn: 'Sale agreement' });
}
if (body.caseType === 'renovation') catalog.push({ code: 'renovation-quote', labelEn: 'Renovation quote' });

const now = new Date().toISOString();
const caseId = body.caseId || `CASE-${String(Date.now()).slice(-6)}`;
const lead = body.leadName;
return [{ json: {
  raw: body,
  caseId,
  now,
  officeAlert: {
    caseId,
    leadName: lead,
    phone: body.phone,
    caseType: body.caseType,
    borrowerProfiles,
    bankTargets,
    message: `New Fillout intake for ${lead} (${caseId}) is ready for office review.`
  },
  clientUpsert: {
    performUpsert: { fieldsToMergeOn: ['Client ID'] },
    records: [{
      fields: {
        'Client ID': body.clientId || `CLIENT-${String(Date.now()).slice(-6)}`,
        'Full name': lead,
        'WhatsApp number': body.phone,
        'Email': body.email || '',
        'Preferred language': body.preferredLanguage || 'he',
      }
    }]
  },
  caseUpsert: {
    performUpsert: { fieldsToMergeOn: ['Case ID'] },
    records: [{
      fields: {
        'Case ID': caseId,
        'Lead name': lead,
        'Spouse name': body.spouseName || '',
        'Phone': body.phone,
        'Email': body.email || '',
        'Case type': body.caseType,
        'Borrower profiles': borrowerProfiles,
        'Current stage': 'intake-submitted',
        'Assigned staff': body.assignedTo || '',
        'Missing items count': catalog.length,
        'Client portal status': 'not-invited',
        'Fillout submission id': body.submissionId,
        'Notes': body.notes || '',
      }
    }]
  },
  caseDocumentsCreate: {
    records: catalog.map((doc) => ({
      fields: {
        'Case link': [caseId],
        'Document code': doc.code,
        'Required?': true,
        'Status': 'not-uploaded',
        'Review notes': '',
      }
    }))
  },
  activityLogCreate: {
    records: [{
      fields: {
        'Case link': [caseId],
        'Actor': 'n8n',
        'Event type': 'fillout_intake_received',
        'Summary': `Fillout intake received for ${lead}`,
        'Source system': 'Fillout',
        'Timestamp': now,
      }
    }]
  }
}}];
